import{_ as a,o as t,c as r,al as o}from"./chunks/framework.3KaqW_hl.js";const p=JSON.parse('{"title":"Créer un Badge Utilisateur Boks (DIY)","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/create_user_tag.md","filePath":"fr/guide/create_user_tag.md"}'),l={name:"fr/guide/create_user_tag.md"};function i(s,e,c,n,u,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="creer-un-badge-utilisateur-boks-diy" tabindex="-1">Créer un Badge Utilisateur Boks (DIY) <a class="header-anchor" href="#creer-un-badge-utilisateur-boks-diy" aria-label="Permalink to &quot;Créer un Badge Utilisateur Boks (DIY)&quot;">​</a></h1><p>Ce guide explique comment transformer un badge NFC standard en &quot;Badge Utilisateur&quot; compatible avec votre Boks, permettant l&#39;ouverture de la porte via le lecteur NFC.</p><h2 id="pre-requis" tabindex="-1">Pré-requis <a class="header-anchor" href="#pre-requis" aria-label="Permalink to &quot;Pré-requis&quot;">​</a></h2><ol><li><strong>Un Badge NFC Vierge :</strong><ul><li>Type : <strong>Mifare Classic 1K</strong> (UID 4 octets).</li><li><em>Note :</em> Pas besoin de badge &quot;Magic&quot; (UID modifiable) sauf si vous voulez cloner un badge existant. Un badge Mifare standard à 1€ suffit.</li></ul></li><li><strong>Un Smartphone Android avec NFC.</strong></li><li><strong>L&#39;application :</strong> <a href="https://play.google.com/store/apps/details?id=de.syss.MifareClassicTool" target="_blank" rel="noreferrer">Mifare Classic Tool (MCT)</a>.</li></ol><hr><h2 id="la-technique" tabindex="-1">La Technique <a class="header-anchor" href="#la-technique" aria-label="Permalink to &quot;La Technique&quot;">​</a></h2><p>La Boks ne lit pas n&#39;importe quel badge. Pour être détecté, le badge doit posséder une <strong>clé spécifique</strong> sur son <strong>Secteur 1</strong>. Sans cette clé, la Boks ignore le badge.</p><ul><li><strong>Clé A (Secteur 1) :</strong> <code>873D9EF6C1A0</code></li></ul><hr><h2 id="procedure-pas-a-pas-avec-mct" tabindex="-1">Procédure pas à pas (avec MCT) <a class="header-anchor" href="#procedure-pas-a-pas-avec-mct" aria-label="Permalink to &quot;Procédure pas à pas (avec MCT)&quot;">​</a></h2><h3 id="etape-1-ajouter-la-cle-dans-mct" tabindex="-1">Étape 1 : Ajouter la Clé dans MCT <a class="header-anchor" href="#etape-1-ajouter-la-cle-dans-mct" aria-label="Permalink to &quot;Étape 1 : Ajouter la Clé dans MCT&quot;">​</a></h3><ol><li>Lancez <strong>Mifare Classic Tool</strong>.</li><li>Allez dans <strong>&quot;Edit/Analyze Key File&quot;</strong>.</li><li>Ouvrez le fichier <code>std.keys</code> (ou créez-en un nouveau).</li><li>Ajoutez une nouvelle ligne avec la clé suivante : <code>873D9EF6C1A0</code></li><li>Appuyez sur l&#39;icône <strong>Disquette</strong> pour sauvegarder.</li></ol><h3 id="etape-2-ecrire-la-cle-sur-le-badge" tabindex="-1">Étape 2 : Écrire la Clé sur le Badge <a class="header-anchor" href="#etape-2-ecrire-la-cle-sur-le-badge" aria-label="Permalink to &quot;Étape 2 : Écrire la Clé sur le Badge&quot;">​</a></h3><ol><li>Retournez au menu principal et choisissez <strong>&quot;Write Tag&quot;</strong>.</li><li>Sélectionnez le mode <strong>&quot;Write Block&quot;</strong>.</li><li>Dans le champ <strong>Block Number</strong>, entrez : <strong><code>7</code></strong>. <ul><li><em>Pourquoi 7 ?</em> C&#39;est le dernier bloc du Secteur 1, qui contient les clés d&#39;accès.</li></ul></li><li>Dans le champ <strong>Data (Hex)</strong>, copiez-collez exactement ceci : <code>873D9EF6C1A07F078840FFFFFFFFFFFF</code><ul><li><code>873D9EF6C1A0</code> : La Clé A (User Scan).</li><li><code>7F078840</code> : Les permissions (Access Bits).</li><li><code>FFFFFFFFFFFF</code> : La Clé B (Défaut).</li></ul></li><li>Posez votre badge vierge sur le lecteur NFC de votre téléphone.</li><li>Appuyez sur <strong>&quot;Write Block&quot;</strong>.</li><li>MCT va vous demander quelles clés utiliser pour accéder au badge (&quot;Map Keys to Sectors&quot;). <ul><li>Sélectionnez le fichier <code>std.keys</code> (qui contient <code>FFFFFFFFFFFF</code>, la clé par défaut des badges vierges).</li><li>Lancez le mapping/écriture.</li></ul></li><li>Confirmez l&#39;avertissement (&quot;Writing to Sector Trailer...&quot;).</li></ol><hr><h2 id="utilisation-avec-le-boks-sdk" tabindex="-1">Utilisation avec le Boks SDK <a class="header-anchor" href="#utilisation-avec-le-boks-sdk" aria-label="Permalink to &quot;Utilisation avec le Boks SDK&quot;">​</a></h2><p>Une fois votre badge préparé :</p><ol><li>Utilisez la méthode <code>controller.scanNFCTags()</code>.</li><li>Posez votre badge sur la Boks (la LED bleue clignote).</li><li>Vous devriez recevoir une notification <code>NotifyNfcTagFoundPacket</code> avec l&#39;UID du badge (ex: <code>A1B2C3D4</code>).</li><li>Utilisez la méthode <code>controller.registerNfcTag()</code> avec cet UID pour l&#39;ajouter à la mémoire de la Boks.</li><li>C&#39;est fini ! Votre badge ouvre maintenant la porte.</li></ol>',18)])])}const h=a(l,[["render",i]]);export{p as __pageData,h as default};
